        if (data.pageNumber > 1) {
          drawCostSheetHeaders(doc);
        }
      }
    });

    let finalY = doc.lastAutoTable.finalY + 5;
    const estimatedFooterHeight = 60; 

    if (finalY + estimatedFooterHeight > pageHeight) {
      doc.addPage();
      drawCostSheetHeaders(doc);
      finalY = 55;
    }

    doc.autoTable({
      startY: finalY,
      head: [
