    };

    currentY = drawTextSection("QUADRO DE ATIVIDADES SERVIÇO:", formData.reportActivities, currentY);
    currentY = drawTextSection("SERVIÇOS DE PREVENTIVO DE ORIENTAÇÃO E ADVERTÊNCIA:", formData.reportGuidance, currentY);
    currentY = drawTextSection("DISTRIBUIÇÃO DO EFETIVO:", formData.reportDistribution, currentY);
    currentY = drawTextSection("SUGESTÕES:", formData.reportSuggestions, currentY);

    // Signature
    if (currentY + 40 > pageHeight) {
      doc.addPage();
      addCbmpaHeader(doc);
      currentY = 40;
    }

    const sigY = currentY + 30;
    drawSignatureWithBoldHighlight(doc, formData.issuerName, formData.issuerWarName, formData.issuerRank, 105, sigY);
    doc.setFont("helvetica", "normal");
    doc.text("Comandante da Prevenção", 105, sigY + 5, { align: "center" });

    window.open(doc.output('bloburl'), '_blank');
  }
};

