        </div>
        {isAiLoading && <div className="fixed inset-0 bg-black/20 backdrop-blur-[2px] z-[60] flex items-center justify-center"><div className="bg-white p-4 rounded-lg shadow-xl flex items-center gap-3"><Sparkles className="animate-pulse text-yellow-500"/><span className="font-bold">IA trabalhando...</span></div></div>}
      </main>
    </div>
  );
};
