    doc.text("    Planilha de pagamento", leftMargin, startY + 35);
    doc.text("    Escala de serviço", leftMargin, startY + 40);
    doc.text(`    NS ${formData.memoNs || '_____'} – SEOP/COP`, leftMargin, startY + 45);
