    const totalCount = tableRows.length;
    const firstPageLimit = totalCount <= 11 ? 11 : 20;
    const nextPageLimit = 22;

    let startIdx = 0;
    let pageNum = 0;

    while (startIdx < totalCount) {
      if (pageNum > 0) doc.addPage();

      const isFirstPage = pageNum === 0;
      const currentLimit = isFirstPage ? firstPageLimit : nextPageLimit;
      const currentChunk = tableRows.slice(startIdx, startIdx + currentLimit);
      startIdx += currentLimit;

      const isLastChunk = startIdx >= totalCount;

