    currentY = drawSectionHeader("7. CONSIDERAÇÕES FINAIS", currentY);
    doc.rect(10, currentY, 190, 20);
    doc.setFont("helvetica", "normal");
    doc.setFontSize(7);
    doc.text("OBS-1: Todos os espaços deste relatório deverão ser devidamente preenchidos...", 12, currentY + 4, {maxWidth: 186});
    doc.text("OBS-2: Quando em Operações(Diárias), o Cmt deverá relatar o horário...", 12, currentY + 12, {maxWidth: 186});
    doc.text("OBS-3: Este modelo de Relatório servirá de Padrão para todas as UBM's...", 12, currentY + 16, {maxWidth: 186});

    currentY += 25;
    if (currentY > 230) { doc.addPage(); currentY = 40; }
    doc.setFontSize(9);
    doc.text(`BELÉM – PA, ${dateString}`, 190, currentY, { align: "right" });
    currentY += 50; 
    drawSignatureWithBoldHighlight(doc, formData.issuerName, formData.issuerWarName, formData.issuerRank, 105, currentY);
    doc.setFont("helvetica", "normal");
    doc.text("CMT DA OPERAÇÃO/EXTRAORDINÁRIA", 105, currentY + 5, { align: "center" });

    window.open(doc.output('bloburl'), '_blank');
  }
};
